const input = $input.first().json;

const message = {
  user_id: input.user_id || 'anonymous',
  user_name: input.user_name || 'Employee',
  user_email: input.user_email || '',
  department: input.department || 'unknown',
  role: input.role || '',
  question: input.message || input.question || '',
  conversation_id: input.conversation_id || `CONV-${Date.now()}`,
  message_history: input.history || [],
  is_onboarding: input.is_onboarding || false,
  days_since_hire: input.days_since_hire || null,
  timestamp: new Date().toISOString()
};

return [{ json: message }];

const articles = $input.first().json || [];
const articleArray = Array.isArray(articles) ? articles : [articles];

const context = articleArray.map(a => 
  `[${a.category}] ${a.title}:\n${a.content}`
).join('\n\n---\n\n');

const userMsg = $('Parse Chat Message').item.json;

return [{
  json: {
    ...userMsg,
    knowledge_context: context.substring(0, 8000)
  }
}];

const aiRaw = $input.first().json;
const userMsg = $('Parse Chat Message').item.json;

let parsed;
try {
  const output = typeof aiRaw.output === 'string' ? aiRaw.output : JSON.stringify(aiRaw.output);
  const cleaned = output.replace(/```json\n?|```/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = {
    answer: typeof aiRaw.output === 'string' ? aiRaw.output : 'Sorry, I had trouble processing that. Please try rephrasing your question.',
    category: 'GENERAL',
    confidence: 0.5,
    escalate: false,
    escalate_to: null,
    sources: [],
    suggested_followups: []
  };
}

return [{
  json: {
    conversation_id: userMsg.conversation_id,
    user_id: userMsg.user_id,
    question: userMsg.question,
    ...parsed,
    timestamp: new Date().toISOString()
  }
}];

